\cosh^2 x - \sinh^2 x
&= (\cosh x + \sinh x)(\cosh x - \sinh x)\\
&= (\frac{e^x+e^{-x}}{2} + \frac{e^x-e^{-x}}{2})
   (\frac{e^x+e^{-x}}{2} - \frac{e^x-e^{-x}}{2})\\
&= \frac{e^x+e^{-x} + e^x-e^{-x}}{2}
   \frac{e^x+e^{-x} - e^x+e^{-x}}{2}\\
&= \frac{2 e^x}{2}
   \frac{2 e^{-x}}{2}\\
&= e^x e^{-x}\\
&= e^{x-x}\\
&= 1
\end{align}

